from strands import Agent

agent = Agent(system_prompt="Tell a very short story.")

for event in agent.stream_async("Write a haiku about the ocean."):
    if "data" in event:
        print(event["data"], end="", flush=True)
print()

from strands import tool
from strands.types.tools import ToolSpec

@tool(
    name="weather",
    description="Get weather for a city. Returns temperature and condition.",
)
def get_weather(city: str) -> dict:
    return {"temperature_celsius": 20, "condition": "sunny"}
